{"file_text": "@using sv_1e467f8c6ba04580b722abc038980af7.Services
@inject IJSRuntime JS

<div class="message-list" @ref="scrollContainer" @onscroll="HandleScroll">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }

    @foreach (var message in Messages)
    {
        var replyCount = ThreadSummaries
            .FirstOrDefault(t => t.RootMessageId == message.Id)?.ReplyCount ?? 0;

        <MessageItem Message="message"
                     ThreadReplyCount="replyCount"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference scrollContainer;
    private bool hasRegisteredObserver;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await JS.InvokeVoidAsync("eval", """
                window.__chatScrollToBottom = (el) => { if (el) el.scrollTop = el.scrollHeight; };
            """);
            await ScrollToBottom();
        }
    }

    public async Task ScrollToBottom()
    {
        try
        {
            await JS.InvokeVoidAsync("__chatScrollToBottom", scrollContainer);
        }
        catch { /* Element may not be rendered yet */ }
    }

    private async Task HandleScroll()
    {
        try
        {
            var scrollTop = await JS.InvokeAsync<double>("eval",
                $"document.querySelector('[b-{scrollContainer.Id}]')?.scrollTop ?? -1");

            // Fallback: use a simpler check via element reference
            if (scrollTop <= 1 && !IsLoadingMore && Messages.Count > 0)
            {
                await OnLoadMore.InvokeAsync();
            }
        }
        catch
        {
            // If JS interop fails on scroll, silently ignore
        }
    }
}
